"use strict";parserFactory.register("snoutandco.ca",()=>new SnoutandcoParser);class SnoutandcoParser extends Parser{constructor(){super()}async getChapterUrls(t){let e=t.querySelector("ul.list-group"),r=util.hyperlinksToChapterList(e);return SnoutandcoParser.titles=new Map,r.forEach(t=>SnoutandcoParser.titles.set(t.sourceUrl,t.title)),r}findContent(t){return Parser.findConstrutedContent(t)}extractTitleImpl(t){return t.querySelector("h1#book-title")}async fetchChapter(t){let e=new URL(t).searchParams,r=`https://snoutandco.ca/${e.get("folder")}/chapters/${e.get("chapter")}`,n=await HttpClient.fetchText(r);return this.buildChapter(n,t)}buildChapter(t,e){let r=Parser.makeEmptyDocForContent(e),n=r.dom.createElement("h1");return n.textContent=SnoutandcoParser.titles.get(e),r.content.appendChild(n),Parser.addTextToChapterContent(r,t),r.dom}}